from typing import List
from itertools import pairwise

class Solution:
    def minAbsDiff(self, grid: List[List[int]], k: int) -> List[List[int]]:
        # Get dimensions of the grid
        rows, cols = len(grid), len(grid[0])
      
        # Initialize result matrix with dimensions for all possible k×k subgrids
        result = [[0] * (cols - k + 1) for _ in range(rows - k + 1)]
      
        # Iterate through all possible starting positions for k×k subgrids
        for start_row in range(rows - k + 1):
            for start_col in range(cols - k + 1):
                # Collect all values from the current k×k subgrid
                subgrid_values = []
                for row in range(start_row, start_row + k):
                    for col in range(start_col, start_col + k):
                        subgrid_values.append(grid[row][col])
              
                # Sort values to find minimum difference between consecutive elements
                subgrid_values.sort()
              
                # Calculate minimum absolute difference between any two distinct values
                # Using pairwise to get consecutive pairs after sorting
                min_difference = min(
                    (abs(first - second) 
                     for first, second in pairwise(subgrid_values) 
                     if first != second), 
                    default=0
                )
              
                # Store the minimum difference for this subgrid
                result[start_row][start_col] = min_difference
      
        return result

class Solution:
  def numberOfSubmatrices(self, grid: list[list[str]]) -> int:
    m = len(grid)
    n = len(grid[0])
    ans = 0
    # x[i][j] := the number of 'X' in grid[0..i)[0..j)
    x = [[0] * (n + 1) for _ in range(m + 1)]
    # y[i][j] := the number of 'Y' in grid[0..i)[0..j)
    y = [[0] * (n + 1) for _ in range(m + 1)]

    for i, row in enumerate(grid):
      for j, cell in enumerate(row):
        x[i + 1][j + 1] = (cell == 'X') + x[i][j + 1] + x[i + 1][j] - x[i][j]
        y[i + 1][j + 1] = (cell == 'Y') + y[i][j + 1] + y[i + 1][j] - y[i][j]
        if x[i + 1][j + 1] > 0 and x[i + 1][j + 1] == y[i + 1][j + 1]:
          ans += 1

    return ans

class Solution:
  def countSubmatrices(self, grid: list[list[int]], k: int) -> int:
    m = len(grid)
    n = len(grid[0])
    ans = 0
    # prefix[i][j] := the sum of matrix[0..i)[0..j)
    prefix = [[0] * (n + 1) for _ in range(m + 1)]

    for i in range(m):
      for j in range(n):
        prefix[i + 1][j + 1] = (grid[i][j] + prefix[i][j + 1] +
                                prefix[i + 1][j] - prefix[i][j])
        if prefix[i + 1][j + 1] <= k:
          ans += 1

    return ans

class Solution:
  def largestSubmatrix(self, matrix: list[list[int]]) -> int:
    ans = 0
    hist = [0] * len(matrix[0])

    for row in matrix:
      # Accumulate the histogram if possible.
      for i, num in enumerate(row):
        hist[i] = 0 if num == 0 else hist[i] + 1

      # Get the sorted histogram.
      sortedHist = sorted(hist)

      # Greedily calculate the answer.
      for i, h in enumerate(sortedHist):
        ans = max(ans, h * (len(row) - i))

    return ans

