class Solution:
    def minNumberOfSeconds(self, mountainHeight: int, workerTimes: List[int]) -> int:


        def can_complete_in_time(time_limit: int) -> bool:

            total_height_reduced = 0

            for worker_time in workerTimes:
                # Calculate maximum rounds this worker can complete within time_limit
                # Using the quadratic formula solution for n
                max_rounds = int(sqrt(2 * time_limit / worker_time + 0.25) - 0.5)
                total_height_reduced += max_rounds

            return total_height_reduced >= mountainHeight

        # Binary search using standard template to find minimum valid time
        left, right = 1, 10**16
        first_true_index = -1

        while left <= right:
            mid = (left + right) // 2
            if can_complete_in_time(mid):
                first_true_index = mid
                right = mid - 1  # Found valid time, try smaller
            else:
                left = mid + 1   # Need more time

        return first_true_index

class UnionFind:
    def __init__(self, n):
        self.p = list(range(n))
        self.size = [1] * n
        self.cnt = n

    def find(self, x):
        if self.p[x] != x:
            self.p[x] = self.find(self.p[x])
        return self.p[x]

    def union(self, a, b):
        pa, pb = self.find(a), self.find(b)
        if pa == pb:
            return False
        if self.size[pa] > self.size[pb]:
            self.p[pb] = pa
            self.size[pa] += self.size[pb]
        else:
            self.p[pa] = pb
            self.size[pb] += self.size[pa]
        self.cnt -= 1
        return True


class Solution:
    def maxStability(self, n: int, edges: List[List[int]], k: int) -> int:
        def check(lim: int) -> bool:
            uf = UnionFind(n)
            for u, v, s, _ in edges:
                if s >= lim:
                    uf.union(u, v)
            rem = k
            for u, v, s, _ in edges:
                if s * 2 >= lim and rem > 0:
                    if uf.union(u, v):
                        rem -= 1
            return uf.cnt == 1

        uf = UnionFind(n)
        mn = 10**6
        for u, v, s, must in edges:
            if must:
                mn = min(mn, s)
                if not uf.union(u, v):
                    return -1
        for u, v, _, _ in edges:
            uf.union(u, v)
        if uf.cnt > 1:
            return -1
        l, r = 1, mn
        while l < r:
            mid = (l + r + 1) >> 1
            if check(mid):
                l = mid
            else:
                r = mid - 1
        return l

