class Solution:
  def replaceValueInTree(self, root: TreeNode | None) -> TreeNode | None:
    levelSums = []

    def dfs(root: TreeNode | None, level: int) -> None:
      if not root:
        return
      if len(levelSums) == level:
        levelSums.append(0)
      levelSums[level] += root.val
      dfs(root.left, level + 1)
      dfs(root.right, level + 1)

    def replace(
        root: TreeNode | None,
        level: int, curr: TreeNode | None,
    ) -> TreeNode | None:
      nextLevel = level + 1
      nextLevelCousinsSum = (
          (levelSums[nextLevel] if nextLevel < len(levelSums) else 0) -
          (root.left.val if root.left else 0) -
          (root.right.val if root.right else 0))
      if root.left:
        curr.left = TreeNode(nextLevelCousinsSum)
        replace(root.left, level + 1, curr.left)
      if root.right:
        curr.right = TreeNode(nextLevelCousinsSum)
        replace(root.right, level + 1, curr.right)
      return curr

    dfs(root, 0)
    return replace(root, 0, TreeNode(0))

class Solution:
  def kthLargestLevelSum(self, root: TreeNode | None, k: int) -> int:
    levelSums = []

    def dfs(root: TreeNode | None, level: int) -> None:
      if not root:
        return
      if len(levelSums) == level:
        levelSums.append(0)
      levelSums[level] += root.val
      dfs(root.left, level + 1)
      dfs(root.right, level + 1)

    dfs(root, 0)
    if len(levelSums) < k:
      return -1

    return sorted(levelSums, reverse=True)[k - 1]

class Solution {
public:
    int maxUniqueSplit(string s) {
        unordered_set<string> used;
        return backtrack(s, 0, used);
    }
    
    int backtrack(const string& s, int start, unordered_set<string>& used) {
        if (start == s.length()) {
            return 0;
        }
        
        int maxSplit = 0;
        
        string current = "";
        for (int i = start; i < s.length(); ++i) {
            current += s[i];
            if (used.find(current) == used.end()) {
                used.insert(current);
                maxSplit = max(maxSplit, 1 + backtrack(s, i + 1, used));
                used.erase(current);
            }
        }
        
        return maxSplit;
    }
};

class Solution {
public:
    char findKthBit(int n, int k) {
        if (n == 1) {
            return '0';
        }
        
        int length = (1 << n) - 1;
        int mid = length / 2 + 1;
        
        if (k == mid) {
            return '1';
        } else if (k < mid) {
            return findKthBit(n - 1, k);
        } else {
            int mirroredIndex = length - k + 1;
            char mirroredBit = findKthBit(n - 1, mirroredIndex);
            return mirroredBit == '0' ? '1' : '0';
        }
    }
};

